<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>GitHub Profile - Praful Thakur</title>
<style>
  * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif;
    background-color: #0d1117;
    color: #c9d1d9;
    min-height: 100vh;
  }

  /* Top Navigation */
  .top-nav {
    background-color: #161b22;
    border-bottom: 1px solid #30363d;
    height: 62px;
    display: flex;
    align-items: center;
    padding: 0 32px;
    position: sticky;
    top: 0;
    z-index: 100;
  }

  .nav-logo {
    display: flex;
    align-items: center;
    gap: 16px;
  }

  .github-icon {
    width: 32px;
    height: 32px;
    fill: #c9d1d9;
  }

  .nav-links {
    display: flex;
    align-items: center;
    gap: 16px;
    margin-left: 16px;
  }

  .nav-links a {
    color: #c9d1d9;
    text-decoration: none;
    font-size: 14px;
    font-weight: 500;
    padding: 6px 12px;
    border-radius: 6px;
    transition: background-color 0.2s;
    display: flex;
    align-items: center;
    gap: 4px;
  }

  .nav-links a:hover {
    background-color: rgba(255,255,255,0.08);
  }

  .dropdown-arrow {
    font-size: 10px;
    opacity: 0.7;
  }

  .nav-right {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-left: auto;
  }

  .search-box {
    background-color: #0d1117;
    border: 1px solid #30363d;
    border-radius: 6px;
    padding: 5px 12px;
    color: #c9d1d9;
    font-size: 14px;
    width: 280px;
    height: 32px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .search-box input {
    background: none;
    border: none;
    color: #c9d1d9;
    font-size: 14px;
    width: 100%;
    outline: none;
  }

  .search-box input::placeholder {
    color: #8b949e;
  }

  .search-slash {
    background-color: #30363d;
    border-radius: 4px;
    padding: 1px 6px;
    font-size: 12px;
    color: #8b949e;
    border: 1px solid #484f58;
  }

  .sign-in, .sign-up {
    color: #c9d1d9;
    text-decoration: none;
    font-size: 14px;
    font-weight: 500;
    padding: 5px 16px;
    border-radius: 6px;
  }

  .sign-up {
    border: 1px solid #c9d1d9;
  }

  .sign-up:hover {
    border-color: #c9d1d9;
    background: rgba(255,255,255,0.08);
  }

  .nav-profile-icon {
    width: 20px;
    height: 20px;
    fill: #c9d1d9;
  }

  /* Sub Navigation */
  .sub-nav {
    background-color: #161b22;
    border-bottom: 1px solid #30363d;
    padding: 0 32px;
    display: flex;
    gap: 4px;
    position: sticky;
    top: 62px;
    z-index: 99;
  }

  .sub-nav a {
    color: #8b949e;
    text-decoration: none;
    font-size: 14px;
    padding: 12px 16px;
    display: flex;
    align-items: center;
    gap: 6px;
    border-bottom: 2px solid transparent;
    transition: color 0.2s;
  }

  .sub-nav a:hover {
    color: #c9d1d9;
  }

  .sub-nav a.active {
    color: #f0f6fc;
    border-bottom-color: #f78166;
    font-weight: 600;
  }

  .sub-nav .count {
    background-color: #30363d;
    color: #c9d1d9;
    border-radius: 10px;
    padding: 1px 8px;
    font-size: 12px;
    font-weight: 500;
  }

  .sub-nav-icon {
    width: 16px;
    height: 16px;
    fill: currentColor;
  }

  /* Main Layout */
  .main-container {
    max-width: 1280px;
    margin: 0 auto;
    padding: 24px 32px;
    display: flex;
    gap: 24px;
  }

  /* Left Sidebar */
  .sidebar {
    width: 296px;
    flex-shrink: 0;
  }

  .avatar-container {
    position: relative;
    margin-bottom: 16px;
  }

  .avatar {
    width: 296px;
    height: 296px;
    border-radius: 50%;
    background: linear-gradient(135deg, #c9a87c 0%, #8b7355 30%, #a68b6b 50%, #7d6b5a 70%, #6b5a4a 100%);
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    border: 1px solid #30363d;
  }

  .avatar-face {
    width: 100%;
    height: 100%;
    position: relative;
    background: linear-gradient(180deg, #d4b896 0%, #c4a07a 40%, #b09070 60%, #8b7060 100%);
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .avatar-face::before {
    content: '';
    position: absolute;
    width: 80px;
    height: 60px;
    background: linear-gradient(180deg, #5a4535 0%, #4a3828 100%);
    border-radius: 40px 40px 0 0;
    top: 30%;
    left: 50%;
    transform: translateX(-50%);
  }

  .status-indicator {
    position: absolute;
    bottom: 8px;
    right: 8px;
    width: 34px;
    height: 34px;
    background-color: #238636;
    border-radius: 50%;
    border: 3px solid #0d1117;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .status-emoji {
    font-size: 16px;
  }

  .profile-name {
    font-size: 26px;
    font-weight: 600;
    color: #f0f6fc;
    line-height: 1.25;
  }

  .profile-username {
    font-size: 20px;
    font-weight: 300;
    color: #8b949e;
    margin-bottom: 16px;
  }

  .follow-btn {
    width: 100%;
    padding: 5px 16px;
    font-size: 14px;
    font-weight: 500;
    color: #f0f6fc;
    background-color: #238636;
    border: 1px solid rgba(63,185,80,0.4);
    border-radius: 6px;
    cursor: pointer;
    margin-bottom: 16px;
    text-align: center;
  }

  .follow-btn:hover {
    background-color: #2ea043;
  }

  .profile-bio {
    font-size: 14px;
    color: #c9d1d9;
    line-height: 1.5;
    margin-bottom: 16px;
  }

  .followers-info {
    display: flex;
    align-items: center;
    gap: 4px;
    font-size: 14px;
    color: #c9d1d9;
    margin-bottom: 16px;
  }

  .followers-icon {
    width: 16px;
    height: 16px;
    fill: #8b949e;
  }

  .followers-info strong {
    font-weight: 600;
  }

  .profile-meta {
    display: flex;
    flex-direction: column;
    gap: 6px;
    margin-bottom: 16px;
  }

  .meta-item {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 14px;
    color: #c9d1d9;
  }

  .meta-icon {
    width: 16px;
    height: 16px;
    fill: #8b949e;
    flex-shrink: 0;
  }

  .meta-item a {
    color: #58a6ff;
    text-decoration: none;
    word-break: break-all;
  }

  .meta-item a:hover {
    text-decoration: underline;
  }

  .block-report {
    font-size: 12px;
    color: #8b949e;
    text-decoration: none;
    margin-top: 8px;
    display: inline-block;
  }

  .block-report:hover {
    color: #58a6ff;
    text-decoration: underline;
  }

  /* Main Content */
  .main-content {
    flex: 1;
    min-width: 0;
  }

  .readme-card {
    border: 1px solid #30363d;
    border-radius: 6px;
    background-color: #0d1117;
  }

  .readme-header {
    padding: 12px 16px;
    border-bottom: 1px solid #30363d;
    font-size: 14px;
    color: #8b949e;
    display: flex;
    align-items: center;
    gap: 4px;
  }

  .readme-body {
    padding: 32px;
  }

  .profile-banner {
    width: 100%;
    height: 120px;
    background: linear-gradient(135deg, #1a1e24 0%, #2d333b 50%, #1a1e24 100%);
    border-radius: 6px;
    margin-bottom: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #8b949e;
    font-size: 14px;
    overflow: hidden;
    position: relative;
  }

  .profile-banner::before {
    content: '';
    position: absolute;
    width: 100%;
    height: 100%;
    background: repeating-linear-gradient(
      45deg,
      transparent,
      transparent 10px,
      rgba(255,255,255,0.02) 10px,
      rgba(255,255,255,0.02) 20px
    );
  }

  .profile-banner img {
    height: 100%;
    width: 100%;
    object-fit: cover;
  }

  .greeting {
    text-align: center;
    font-size: 32px;
    font-weight: 700;
