    border-top: 1px solid #30363d;
    margin: 32px 0;
  }

  .section-title {
    font-size: 22px;
    font-weight: 600;
    color: #f0f6fc;
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .section-emoji {
    font-size: 20px;
  }

  .section-text {
