    color: #c9d1d9;
    line-height: 1.6;
    margin-bottom: 16px;
  }

  .about-list {
    list-style: disc;
    padding-left: 24px;
    margin-bottom: 16px;
  }

  .about-list li {
    font-size: 14px;
    color: #c9d1d9;
    line-height: 1.8;
    margin-bottom: 4px;
  }

  .about-list li strong {
    color: #f0f6fc;
    font-weight: 600;
  }

  .about-list a {
    color: #58a6ff;
    text-decoration: none;
  }

  .about-list a:hover {
    text-decoration: underline;
  }

  /* Tech Stack Icons */
  .tech-icons {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    justify-content: center;
    margin-top: 16px;
  }

  .tech-icon {
    width: 52px;
    height: 52px;
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    font-weight: 700;
    color: #ffffff;
  }

  .tech-python { background: linear-gradient(135deg, #3776AB, #FFD43B); }
  .tech-c { background: #A8B9CC; color: #03599C; }
  .tech-html { background: #E34F26; }
  .tech-bootstrap { background: #7952B3; }
  .tech-git { background: #F05032; }
  .tech-vscode { background: linear-gradient(135deg, #007ACC, #1E90FF); }
  .tech-css { background: #1572B6; }
  .tech-mysql { background: #4479A1; }
  .tech-flask { background: #000000; border: 1px solid #30363d; }
  .tech-postman { background: #FF6C37; }
  .tech-raspberry { background: #C51A4A; }

  /* GitHub Stats Cards */
  .stats-grid {
    display: flex;
    gap: 16px;
    margin-top: 16px;
    flex-wrap: wrap;
  }

  .stats-card {
    background-color: #161b22;
    border: 1px solid #30363d;
    border-radius: 6px;
    padding: 16px;
    flex: 1;
    min-width: 200px;
  }

  .stats-card-title {
    font-size: 14px;
    font-weight: 600;
    color: #f0f6fc;
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .stats-card-title .icon {
    font-size: 16px;
  }

  .stat-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-size: 14px;
    padding: 6px 0;
    border-bottom: 1px solid #21262d;
  }

  .stat-row:last-child {
    border-bottom: none;
  }

  .stat-label {
    color: #8b949e;
    display: flex;
    align-items: center;
    gap: 6px;
  }

  .stat-value {
    color: #f0f6fc;
    font-weight: 600;
  }

  .streak-cards {
    display: flex;
    gap: 16px;
    margin-top: 16px;
    flex-wrap: wrap;
  }

  .streak-card {
    background-color: #161b22;
    border: 1px solid #30363d;
    border-radius: 6px;
    padding: 20px;
    flex: 1;
    min-width: 150px;
    text-align: center;
  }

  .streak-number {
    font-size: 40px;
    font-weight: 700;
    color: #f0f6fc;
    line-height: 1;
  }

  .streak-label {
    font-size: 13px;
    color: #8b949e;
    margin-top: 8px;
  }

  .streak-card.active .streak-number {
    color: #f78166;
  }

  /* Footer */
  .footer {
    margin-top: 40px;
    padding: 24px 0;
    text-align: center;
    font-size: 12px;
    color: #484f58;
    border-top: 1px solid #21262d;
  }
