        .logo-sub {
            font-size: 10px;
            vertical-align: super;
            margin-left: 1px;
        }

        .search-container {
            flex: 1;
            max-width: 640px;
            margin: 0 40px;
            display: flex;
            align-items: center;
        }

        .search-input {
            flex: 1;
            height: 40px;
            padding: 0 16px;
            border: 1px solid #ccc;
            border-right: none;
            border-radius: 20px 0 0 20px;
            font-size: 16px;
            outline: none;
        }

        .search-input:focus {
            border-color: #1c62b9;
        }

        .search-button {
            height: 40px;
            width: 64px;
            background-color: #f8f8f8;
            border: 1px solid #ccc;
            border-radius: 0 20px 20px 0;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .search-button:hover {
            background-color: #f0f0f0;
        }

        .search-icon {
            width: 20px;
            height: 20px;
            background-color: #606060;
            border-radius: 50%;
        }

        .voice-button {
            width: 40px;
            height: 40px;
            background-color: #f2f2f2;
            border-radius: 50%;
            margin-left: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
        }

        .voice-icon {
            width: 12px;
            height: 20px;
            background-color: #606060;
            border-radius: 6px;
        }

        .header-right {
            display: flex;
            align-items: center;
            margin-left: auto;
        }

        .more-button {
            width: 40px;
            height: 40px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            border-radius: 50%;
        }

        .more-button:hover {
            background-color: #f2f2f2;
